import pandas as pd
import numpy as np

def solve(df_employees):
    df = df_employees.copy()
    reference_date = pd.Timestamp('2026-04-01')
    df['hire_date'] = pd.to_datetime(df['hire_date'])
    df['tenure_days'] = (reference_date - df['hire_date']).dt.days
    df['tenure_years'] = (df['tenure_days'] / 365.25).round(1)
    def band(y):
        if y < 2:
            return 'junior'
        elif y <= 5:
            return 'mid'
        else:
            return 'senior'
    df['tenure_band'] = df['tenure_years'].apply(band)
    df['hire_date'] = df['hire_date'].dt.strftime('%Y-%m-%d')
    return df[['employee_id', 'employee_name', 'hire_date', 'tenure_days', 'tenure_years', 'tenure_band']].sort_values('tenure_days', ascending=False).reset_index(drop=True)
